func:
// 1. Extract user safely
let discordUser = "Player";

if (msg.payload && msg.payload.author && msg.payload.author.username) {
    discordUser = msg.payload.author.username;
}

// 2. Extract channel ID (IMPORTANT for reply)
let channelId = msg.payload.channelId;

// 3. Dice logic
let playerRoll = Math.floor(Math.random() * 6) + 1;
let dealerRoll = Math.floor(Math.random() * 6) + 1;

let outcome = "";
let gameResult = "";

if (playerRoll > dealerRoll) {
    outcome = "win";
    gameResult = "🏆 YOU WIN! Reward granted!";
} else if (playerRoll < dealerRoll) {
    outcome = "loss";
    gameResult = "💀 YOU LOSE! Penalty applied!";
} else {
    outcome = "tie";
    gameResult = "🤝 TIE GAME! Try again!";
}

// 4. Build reply message (THIS is what gets sent to Discord)
msg.payload = {
    channelId: channelId,
    content:
        `🎲 **Dice Duel Arena** 🎲
**${discordUser} vs Dealer**

🎲 You: ${playerRoll}
🎲 Dealer: ${dealerRoll}

${gameResult}`
};

// 5. Keep game data for Minecraft part
msg.outcome = outcome;
msg.player = "@a";

return msg;

let rewards = [
    "give " + msg.player + " minecraft:diamond 5",                // Make it rain
    "effect give " + msg.player + " minecraft:regeneration 30 1", // Inspiration
    "give " + msg.player + " minecraft:totem_of_undying 1"         // Another chance
];
// Randomly pick one reward option from our array
msg.payload = rewards[Math.floor(Math.random() * rewards.length)];
return msg;

let penalties = [
    "execute at " + msg.player + " run summon zombie ~ ~ ~",       // Horde
    "effect give " + msg.player + " minecraft:poison 10 1",       // Big loss (Poison)
    "effect give " + msg.player + " minecraft:hunger 15 1"        // Big loss (Hunger)
];
// Rare death mechanic rule (1 in 20 chance)
if (Math.random() < 0.05) {
    penalties.push("kill " + msg.player); // Death
}

msg.payload = penalties[Math.floor(Math.random() * penalties.length)];
return msg;

// 1. Prüfen, ob die Nachricht überhaupt "$dice" ist
let input = String(msg.payload).trim();

if (input !== "$dice") {
    return null; // Beendet den Flow hier, wenn es nicht "$status" ist
}

// 2. Wenn es "$status" war, bereiten wir den RCON-Befehl vor
msg.payload = "list";
return msg;

// 1. Prüfen, ob die Nachricht überhaupt "$status" ist
let input = String(msg.payload).trim();

if (input !== "$status") {
    return null; // Beendet den Flow hier, wenn es nicht "$status" ist
}

// 2. Wenn es "$status" war, bereiten wir den RCON-Befehl vor
msg.payload = "list";
return msg;

// 1. Prüfen, ob die Antwort vom RCON-Node leer oder ein Fehler ist
if (!msg.payload || String(msg.payload).includes("ECONNREFUSED") || String(msg.payload).includes("Timeout")) {

    // Hier der OFFLINE-CODE:
    msg.payload = {
        content: "🔴 **Server Status**\nDer Server ist aktuell **OFFLINE** oder nicht erreichbar."
    };

    return msg;
}

// 2. Wenn der Server Online ist:
let text = String(msg.payload);
let match = text.match(/(\d+)\D+(\d+)/);
let online = match ? match[1] : "0";
let max = match ? match[2] : "?";

msg.payload = {
    content: `🟢 **Server Online**\n👥 **Spieler:** ${online}/${max}`
};

return msg;

// 1. Deine Discord User-ID
const ADMIN_ID = "412683992991531018";

// 2. Prüfen, ob die Nachricht mit "!" beginnt
if (!msg.payload || !msg.payload.startsWith("!")) {
    return null; // Ignoriert normale Nachrichten ohne "!"
}

// 3. Sicherheitscheck: Wer hat geschrieben?
let authorId = msg.authorId || 
               (msg.author ? msg.author.id : null) || 
               (msg.member ? msg.member.id : null);

if (authorId !== ADMIN_ID) {
    // FEHLERMELDUNG FÜR NICHT-ADMINS
    msg.payload = { 
        content: "🚫 **Zugriff verweigert:** Du hast keine Berechtigung, Server-Befehle auszuführen!" 
    };
    return msg.payload; // Diese Nachricht geht direkt zum Discord-Send-Node
}

// 4. WENN ADMIN: Befehl für Minecraft vorbereiten
let command = msg.payload.substring(1).trim();

// Wir setzen ein zweites Ziel-Label (Topic), damit wir später 
// zwischen RCON-Antwort und Fehlermeldung unterscheiden können
msg.topic = "admin_cmd"; 
msg.payload = command; // Eventuell + "\n" falls es noch nicht geht

// Wir schicken die Nachricht an den RCON-Node
node.send([msg, null]); 
return null;

let response = String(msg.payload);

// Falls Minecraft eine Fehlermeldung schickt
if (response.includes("Unknown or incomplete command") || response.trim() === "") {
    msg.payload = {
        content: "💻 **Konsole:** Befehl gesendet, aber keine Bestätigung erhalten (oder Befehl unbekannt)."
    };
} else {
    msg.payload = {
        content: "💻 **Konsole:**\n```\n" + response + "\n```"
    };
}

return msg;

// 1. Variablen definieren
const userId = msg.authorId || (msg.author ? msg.author.id : null);
const parts = msg.payload.trim().split(/\s+/);
const mcName = parts[1];
const now = Date.now();
const cooldown = 24 * 60 * 60 * 1000; // 24 Stunden in Millisekunden

// 2. Prüfen, ob ein Name angegeben wurde
if (!mcName) {
    return [null, { payload: { content: "❌ Bitte gib deinen Namen an: `$daily MeinName`" } }];
}

// 3. Zeit-Check (Die Sperre)
// Wir holen uns die Zeit des letzten Gebrauchs für diesen speziellen User
let lastUsed = context.get("daily_" + userId) || 0;

if (now - lastUsed < cooldown) {
    // Zeit berechnen, wie lange er noch warten muss
    let remainingMs = cooldown - (now - lastUsed);
    let hours = Math.floor(remainingMs / (1000 * 60 * 60));
    let minutes = Math.floor((remainingMs % (1000 * 60 * 60)) / (1000 * 60));

    return [null, { 
        payload: { 
            content: `⏳ **Geduld!** Du hast deine Belohnung heute schon abgeholt. \nDu musst noch **${hours} Stunden und ${minutes} Minuten** warten.` 
        } 
    }];
}

// 4. Wenn der Check bestanden wurde: Neue Zeit speichern
context.set("daily_" + userId, now);

// 5. Befehle vorbereiten
let rconMsg = { payload: "give " + mcName + " diamond 5" };
let discordMsg = { payload: { content: "💎 **Erfolg!** 5 Diamanten wurden an **" + mcName + "** gesendet. Komm morgen wieder!" } };

return [rconMsg, discordMsg];

msg.payload = {
    content: "🎮 **Minecraft-Server Manager v1.0**\n" +
        "--------------------------------------------------\n" +
        "**Spieler-Befehle:**\n" +
        "• `$daily` - Holt deine tägliche Belohnung ab.\n" +
        "• `$dice` - Dice game wird ausgeführt\n\n" +
        "**Admin-Befehle (Nur für Admins):**\n" +
        "• `$status` - Prüft Zeit & Spieleranzahl auf dem Server.\n" +
        "• `!` - Alle andere Befehle die über Minecraft chat auch geht\n" +
        "--------------------------------------------------"
};
return msg;

let times = 5;      // number of blinks
let delay = 200;   // ms between ON/OFF

for (let i = 0; i < times; i++) {
    // ON
    setTimeout(() => {
        node.send({ payload: 1 });
    }, i * delay * 2);

    // OFF
    setTimeout(() => {
        node.send({ payload: 0 });
    }, i * delay * 2 + delay);
}

return null;

// 1. Temperatur für das Dashboard auslesen
let temp = msg.payload.current.temperature_2m;

// 2. Wettercode auslesen
let code = msg.payload.current.weather_code;

// Variablen für Minecraft und LCD vorbereiten
let mcCommand = "/weather clear";
let wetterText = "Sonnig";

// Wetter-Logik (WMO-Codes zu Minecraft-Befehlen)
if (code === 0) {
    mcCommand = "/weather clear";
    wetterText = "Klar";
} else if (code >= 1 && code <= 3) {
    mcCommand = "/weather clear";
    wetterText = "Bewölkt";
} else if ((code >= 51 && code <= 55) || (code >= 61 && code <= 65) || (code >= 80 && code <= 82)) {
    mcCommand = "/weather rain";
    wetterText = "Regen";
} else if (code >= 95 && code <= 99) {
    mcCommand = "/weather thunder";
    wetterText = "Gewitter";
}

// Ausgaben für die nachfolgenden Nodes bauen
msg.temperature = temp;       // Für die Gauge im Dashboard
msg.weatherText = wetterText;   // Für das LCD-Display
msg.payload = mcCommand;       // Das ist der Befehl, der direkt in RCON geht

// Text für Zeile 1: Das Land (z. B. "Luxemburg")
msg.line1 = msg.country;

// Text für Zeile 2: Wettertext + Temperatur (z. B. "Sonnig, 22.4 C")
// .toFixed(1) sorgt dafür, dass die Temperatur nur eine Nachkommastelle hat
msg.line2 = msg.weatherText + ", " + temp.toFixed(1) + "C";

return msg;

// 1. Wir bauen den Text mit den Variablen aus der vorherigen Node zusammen
var nachricht = "🌍 **Wetter-Update!** In **" + msg.country + "** ist es aktuell **" + msg.weatherText + "** bei **" + msg.temperature.toFixed(1) + "°C**.";

// 2. Discord verlangt zwingend ein JSON-Objekt mit dem Feld "content"
msg.payload = {
    "content": nachricht
};

// 3. WICHTIG: Wir sagen der HTTP-Request-Node, dass wir JSON senden
msg.headers = {
    "Content-Type": "application/json"
};

return msg;

let player = global.get("current_player");
let request = global.get("current_request");

let buttonId = "unbekannt";

if (msg.interaction && msg.interaction.custom_id) {
    buttonId = msg.interaction.custom_id;
} else if (msg.payload && msg.payload.customId) {
    buttonId = msg.payload.customId;
} else if (msg.payload && msg.payload.custom_id) {
    buttonId = msg.payload.custom_id;
} else if (msg.customId) {
    buttonId = msg.customId;
}

buttonId = buttonId.toLowerCase().trim();

let command = null;
let discordText = "";

// 1. ANTRAG GENEHMIGT
if (buttonId === "approve_req" || buttonId === "approve") {
    discordText = "✅ **Antrag genehmigt!** Der Befehl wurde in Minecraft ausgeführt.";

    // 🛠️ HIER WAREN DIE KORREKTUREN:
    if (request === "horde") {
        command = "execute at " + player + " run summon zombie ~ ~ ~";
    } else if (request === "rain") {
        command = "weather rain"; // 💎 Vorher stand hier fälschlicherweise Diamant!
    } else if (request === "items") {
        command = "give " + player + " minecraft:diamond 3"; // 🌧️ Falls der Request "items" heißt
    } else if (request === "inspiration") {
        command = "effect give " + player + " minecraft:regeneration 30 1";
    } else if (request === "anotherchance") {
        command = "give " + player + " minecraft:totem_of_undying 1";
    } else {
        command = "say Request von " + player + " verarbeitet.";
    }

    // 2. ANTRAG ABGELEHNT
} else if (buttonId === "deny_req" || buttonId === "deny") {
    discordText = "❌ **Antrag abgelehnt!** Es wurde kein Befehl ausgeführt.";
    command = null;

    // 3. FEHLER/UNBEKANNT
} else {
    discordText = "⚠️ Interaktion verarbeitet (ID: " + buttonId + ")";
}

// Ausgang 1: An das RCON-Node senden (nur wenn command nicht null ist)
let msgMinecraft = command ? { payload: command } : null;

// Ausgang 2: Zurück zu Discord (entfernt auch die Buttons aus der Nachricht)
msg.payload = {
    content: discordText,
    components: [] // Leeres Array löscht die Buttons, damit man nicht doppelt klickt
};

return [msgMinecraft, msg];

// Find the regex matches from the line of text
let match = msg.payload.match(/\<(\w+)\>\s!request\s(\w+)/);

if (match) {
    let player = match[1];
    let requestType = match[2];

    // Save to global memory for Flow B to use later
    global.set("current_player", player);
    global.set("current_request", requestType);

    // Build the message payload for the discord-send-message node
    msg.payload = {
        "content": "⚠️ **New Minecraft Request Pending Approval!**",
        "embeds": [{
            "title": "Action Required",
            "color": 16753920,
            "fields": [
                { "name": "Player", "value": player, "inline": true },
                { "name": "Requested Event", "value": requestType, "inline": true }
            ]
        }],
        "components": [{
            "type": 1,
            "components": [
                { "type": 2, "style": 3, "label": "Approve", "custom_id": "approve_req" },
                { "type": 2, "style": 4, "label": "Deny", "custom_id": "deny_req" }
            ]
        }]
    };

    // Wire this node directly to:
    // 1. discord-send-message (reads msg.payload)
    // 2. rpi-gpio out (sends a separate '1' to turn on LED)
    // 3. i2c-lcd (reads the global variables)
    return msg;
}
return null;

// 1. If server is completely offline or packet drops
if (!msg.payload || typeof msg.payload !== 'object' || !msg.payload.players) {
    let outStatus = { payload: false }; // Updates markdown banner to RED/OFFLINE
    let outCapacity = { payload: "Offline" };
    let outPlayers = { payload: [] }; // Sends empty data array to wipe the table layout cleanly

    // Output 1 gets status + capacity, Output 2 gets the clean clear array
    return [[outStatus, outCapacity], outPlayers];
}

// 2. Server is Online! Extract counts
let onlineCount = msg.payload.players.online !== undefined ? msg.payload.players.online : 0;
let maxCount = msg.payload.players.max !== undefined ? msg.payload.players.max : 20;
let playerArray = msg.payload.players.sample || [];

// 3. Prepare clean telemetry objects
let outStatus = { payload: true }; // Updates markdown banner to GREEN/ONLINE
let outCapacity = { payload: onlineCount + " / " + maxCount };

// MATCH FIX: Match your ui-table column key ('playername') exactly in lowercase
let outPlayers = {
    payload: playerArray.map(p => ({
        "playername": p.name,
        "Status": "Online"
    }))
};

// Output Port 1 gets an array of both layout widgets (Status & Capacity)
// Output Port 2 gets the clean data table player array
return [[outStatus, outCapacity], outPlayers];

let player = global.get("current_player") || "";
let request = global.get("current_request") || "";

msg.payload = {
    active: player !== "",
    player: player,
    request: request
};
return msg;
